				trace.WithAttributes(
					attribute.String("alerting.inhibit_rule.source.fingerprint", inhibitedByFP.String()),
				),
			)
			return true
		}
	}
	ih.marker.SetInhibited(fp)
	span.AddEvent("alert not inhibited")

	return false
